external_knowledge:
- 'top 5 frequently accessed' refers to the models with the highest access counts in the last 30 days.; 
- 'latest evaluations' means the evaluations with the maximum evaluation dates for each model.; 
- 'highest welfare and revenue values' refers to the maximum welfare and revenue values among the latest evaluations for each model.

sql:
SELECT COUNT(*) AS access_count
FROM access_logs
WHERE model_id = (SELECT model_id FROM pricing_models WHERE model_name = 'Simple Pricing');

SELECT COUNT(*) AS active_model_count
FROM pricing_models
WHERE is_active = 1;

SELECT model_name
FROM pricing_models
ORDER BY model_name;

SELECT model_name
FROM pricing_models
ORDER BY created_date DESC;
